{
  "type": "DRAG_FILL",
  "data": {
    "lessonText": "Let's start with a fun challenge to test your Python skills!",
    "challenges": [
      {
        "instruction": "Fill in the blanks to create a simple print statement.",
        "codeTemplate": "print('Hello, ___! My name is ___.')",
        "options": ["World", "Python", "Alice", "Bob"],
        "correctAnswer": "World,Alice",
        "explanation": "This code prints a greeting to the specified name."
      },
      {
        "instruction": "Complete the function to return the sum of two numbers.",
        "codeTemplate": "def add(a, b): return ___ + ___",
        "options": ["a", "b", "a", "b"],
        "correctAnswer": "a,b",
        "explanation": "The function adds the two parameters together."
      },
      {
        "instruction": "Fill in the blanks to create a loop that prints numbers 1 to 5.",
        "codeTemplate": "for i in range(1, ___): print(i)",
        "options": ["5", "6", "4", "7"],
        "correctAnswer": "6",
        "explanation": "The range function goes up to, but does not include, the second argument."
      },
      {
        "instruction": "Complete the conditional statement to check if a number is even.",
        "codeTemplate": "if ___ % 2 == 0: print('Even')",
        "options": ["number", "num", "x", "y"],
        "correctAnswer": "number",
        "explanation": "This checks if the variable 'number' is even."
      }
    ]
  }
}
